package main

import (
    "fmt"
    "slices"
)

// ---- Basic generics ----
func Print[T any](value T) {
    fmt.Println(value)
}

// ---- Generic function with constraints ----
func Max[T int | float64](a, b T) T {
    if a > b {
        return a
    }
    return b
}

// ---- Generic stack ----
type Stack[T any] struct {
    items []T
}

func (s *Stack[T]) Push(item T) {
    s.items = append(s.items, item)
}

func (s *Stack[T]) Pop() T {
    if len(s.items) == 0 {
        var zero T
        return zero
    }
    last := s.items[len(s.items)-1]
    s.items = s.items[:len(s.items)-1]
    return last
}

func (s *Stack[T]) Peek() T {
    if len(s.items) == 0 {
        var zero T
        return zero
    }
    return s.items[len(s.items)-1]
}

// ---- Generic function with type constraint ----
type Number interface {
    int | int64 | float64 | float32
}

func Sum[T Number](values []T) T {
    var sum T
    for _, v := range values {
        sum += v
    }
    return sum
}

// ---- Generic map function ----
func Map[T any, U any](items []T, fn func(T) U) []U {
    result := make([]U, len(items))
    for i, item := range items {
        result[i] = fn(item)
    }
    return result
}

// ---- Filter function ----
func Filter[T any](items []T, pred func(T) bool) []T {
    result := []T{}
    for _, item := range items {
        if pred(item) {
            result = append(result, item)
        }
    }
    return result
}

func main() {
    // Basic usage
    Print("hello")
    Print(42)
    Print(3.14)

    // Max
    fmt.Println("Max(5, 10):", Max(5, 10))
    fmt.Println("Max(3.14, 2.71):", Max(3.14, 2.71))

    // Stack
    s := Stack[int]{}
    s.Push(1)
    s.Push(2)
    s.Push(3)
    fmt.Println("Stack pop:", s.Pop())
    fmt.Println("Stack peek:", s.Peek())

    // String stack
    ss := Stack[string]{}
    ss.Push("a")
    ss.Push("b")
    fmt.Println("String stack pop:", ss.Pop())

    // Sum
    ints := []int{1, 2, 3, 4, 5}
    floats := []float64{1.1, 2.2, 3.3}
    fmt.Println("Sum ints:", Sum(ints))
    fmt.Println("Sum floats:", Sum(floats))

    // Map
    doubled := Map([]int{1, 2, 3, 4, 5}, func(n int) int { return n * 2 })
    fmt.Println("Doubled:", doubled)

    // Filter
    evens := Filter([]int{1, 2, 3, 4, 5, 6}, func(n int) bool { return n%2 == 0 })
    fmt.Println("Evens:", evens)

    // slices package (Go 1.21+)
    sorted := slices.Sorted([]int{3, 1, 4, 1, 5})
    fmt.Println("Sorted:", sorted)
}

