package main

import "fmt"

func Find[T any](items []T, pred func(T) bool) (T, bool) {
    for _, item := range items {
        if pred(item) {
            return item, true
        }
    }
    var zero T
    return zero, false
}

func main() {
    ints := []int{1, 2, 3, 4}
    result, found := Find(ints, func(n int) bool { return n > 2 })
    fmt.Printf("Find >2: %d, %v\n", result, found)

    strings := []string{"a", "b", "c"}
    result2, found2 := Find(strings, func(s string) bool { return s == "d" })
    fmt.Printf("Find 'd': %q, %v\n", result2, found2)
}
